<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\AuditQueryRepositoryInterface;
final class PdoAuditQueryRepository extends AbstractPdoRepository implements AuditQueryRepositoryInterface{private function many(string$q,array$p):array{return$this->stmt($q,$p)->fetchAll(\PDO::FETCH_ASSOC);}public function listByEntity(string$e,int$id):array{return$this->many('SELECT * FROM auditoria_eventos WHERE entidad=:e AND entidad_id=:i ORDER BY created_at',['e'=>$e,'i'=>$id]);}public function listByScannerId(int$id):array{return$this->listByEntity('scanner',$id);}public function listByMovementId(int$id):array{return$this->listByEntity('scanner_movimiento',$id);}public function listByActorId(int$id):array{return$this->many('SELECT * FROM auditoria_eventos WHERE usuario_id=:i ORDER BY created_at',['i'=>$id]);}public function listByDateRange(\DateTimeImmutable$f,\DateTimeImmutable$t):array{return$this->many('SELECT * FROM auditoria_eventos WHERE created_at BETWEEN :f AND :t ORDER BY created_at',['f'=>$f->format('Y-m-d H:i:s.u'),'t'=>$t->format('Y-m-d H:i:s.u')]);}}
